/**
 * Tool Argument Autocorrect - Validates and auto-fixes common tool argument mistakes.
 *
 * Common errors this catches:
 * 
 * Edit tool:
 * - Using `old_text`/`new_text` (snake_case) instead of `oldText`/`newText` (camelCase)
 * - Missing `edits` array wrapper
 * 
 * Write tool:
 * - Using `file` instead of `path`
 */
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

type EditArgs = {
  edits?: Array<{ oldText?: unknown; newText?: unknown }>;
  oldText?: unknown;
  newText?: unknown;
  path?: string;
  old_text?: unknown;
  new_text?: unknown;
  [key: string]: unknown;
};

type WriteArgs = {
  path?: string;
  content?: unknown;
  file?: string;
  [key: string]: unknown;
};

export default function (pi: ExtensionAPI) {
  pi.on("tool_call", async (event, ctx) => {
    const input = event.input as Record<string, unknown>;

    // Handle edit tool corrections
    if (event.toolName === "edit") {
      const editInput = input as EditArgs;
      const hasSnakeCase = editInput.old_text !== undefined || editInput.new_text !== undefined;
      const missingEdits = editInput.edits === undefined && (editInput.oldText !== undefined || editInput.newText !== undefined || hasSnakeCase);

      if (!hasSnakeCase && !missingEdits) return;

      // Try to auto-correct
      if (hasSnakeCase && editInput.path !== undefined) {
        const corrected = {
          edits: [{
            oldText: editInput.old_text,
            newText: editInput.new_text,
          }],
          path: editInput.path,
        };

        ctx.ui.notify("Auto-corrected edit tool: wrapped old_text/new_text in edits array", "info");

        event.input.edits = corrected.edits;
        event.input.oldText = corrected.edits[0].oldText;
        event.input.newText = corrected.edits[0].newText;
        if (editInput.path) {
          event.input.path = corrected.path;
        }
      } else if (missingEdits && editInput.oldText !== undefined && editInput.newText !== undefined && editInput.path !== undefined) {
        const corrected = {
          edits: [{
            oldText: editInput.oldText,
            newText: editInput.newText,
          }],
          path: editInput.path,
        };

        ctx.ui.notify("Auto-corrected edit tool: wrapped oldText/newText in edits array", "info");

        Object.keys(event.input).forEach(key => delete event.input[key]);
        event.input.edits = corrected.edits;
        event.input.path = corrected.path;
      }
      return;
    }

    // Handle write tool corrections
    if (event.toolName === "write") {
      const writeInput = input as WriteArgs;

      if (writeInput.file !== undefined && writeInput.path === undefined) {
        ctx.ui.notify("Auto-corrected write tool: renamed 'file' to 'path'", "info");
        event.input.path = writeInput.file;
        delete event.input.file;
      }
      return;
    }
  });
}

