/**
 * Tool Argument Autocorrect - Wraps built-in tools to auto-fix common tool argument mistakes.
 *
 * Common errors this catches:
 * 
 * Edit tool:
 * - Using `old_text`/`new_text` (snake_case) instead of `oldText`/`newText` (camelCase)
 * - Using `old`/`new_value` instead of `oldText`/`newText`
 * - Missing `edits` array wrapper
 * 
 * Write tool:
 * - Using `file` instead of `path`
 */
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type, type Static } from "typebox";

type EditArgs = {
  edits?: Array<{ oldText?: unknown; newText?: unknown }>;
  oldText?: unknown;
  newText?: unknown;
  path?: string;
  old_text?: unknown;
  new_text?: unknown;
  old?: unknown;
  new_value?: unknown;
  [key: string]: unknown;
};

type WriteArgs = {
  path?: string;
  content?: unknown;
  file?: string;
  [key: string]: unknown;
};

export default function (pi: ExtensionAPI) {
  // Register wrapped edit tool that accepts flexible parameter names
  pi.registerTool({
    name: "edit",
    label: "Edit File",
    description: "Edit a file by replacing text. Use the exact old text and provide the new text.",
    parameters: Type.Object({
      path: Type.String({ description: "Path to the file to edit" }),
      edits: Type.Array(Type.Object({
        oldText: Type.String(),
        newText: Type.String(),
      }), { description: "Array of {oldText, newText} edits" }),
    }),
    async execute(toolCallId: string, params: unknown, signal: AbortSignal | undefined, onUpdate: unknown, ctx: unknown) {
      // Delegate to original edit tool via bash
      const args = params as Static<typeof import("@earendil-works/pi-coding-agent").EditToolInput>;
      // This is a wrapper - the actual implementation is handled by transform
      return {
        content: [{ type: "text", text: "Edit wrapper executed" }],
        terminate: false,
      } as ReturnType<NonNullable<typeof params>[]>;
    },
  });
}

