/**
 * Tool Argument Autocorrect - Wraps built-in tools to auto-fix common tool argument mistakes.
 *
 * Common errors this catches:
 * 
 * Edit tool:
 * - Using `old_text`/`new_text` (snake_case) instead of `oldText`/`newText` (camelCase)
 * - Using `old`/`new_value` instead of `oldText`/`newText`
 * - Missing `edits` array wrapper
 * 
 * Write tool:
 * - Using `file` instead of `path`
 */
import type { ExtensionAPI, ToolDefinition } from "@earendil-works/pi-coding-agent";
import { Type, type Static } from "typebox";

type FlexibleEditArgs = {
  edits?: Array<{ oldText?: unknown; newText?: unknown }>;
  oldText?: unknown;
  newText?: unknown;
  path?: string;
  old_text?: unknown;
  new_text?: unknown;
  old?: unknown;
  new_value?: unknown;
  file_path?: string;
  [key: string]: unknown;
};

export default function (pi: ExtensionAPI) {
  // Create a wrapped edit tool that handles all parameter variations
  const wrappedEditTool: ToolDefinition = {
    name: "edit",
    label: "Edit File",
    description: "Edit a file using exact text replacement. Handles flexible parameter formats.",
    parameters: Type.Object({
      path: Type.String({ description: "Path to the file to edit" }),
      edits: Type.Array(Type.Object({
        oldText: Type.String(),
        newText: Type.String(),
      }), { description: "Array of {oldText, newText} edits" }),
    }),
    prepareArguments(args: unknown): Static<typeof import("@earendil-works/pi-coding-agent").EditToolInput> {
      const input = args as FlexibleEditArgs;

      // Handle JSON string edits
      let editsArray = input.edits;
      if (typeof input.edits === "string") {
        try {
          const parsed = JSON.parse(input.edits);
          if (Array.isArray(parsed)) editsArray = parsed;
        } catch { /* ignore */ }
      }

      // Build edits array from any supported format
      const edits: Array<{ oldText: string; newText: string }> = Array.isArray(editsArray) ? [...editsArray] : [];

      // Handle all legacy formats for old/new text
      let hasLegacyText = false;
      if (typeof input.oldText === "string" && typeof input.newText === "string") {
        edits.push({ oldText: input.oldText, newText: input.newText });
        hasLegacyText = true;
      }
      if (typeof input.old_text === "string" && typeof input.new_text === "string") {
        edits.push({ oldText: input.old_text, newText: input.new_text });
        hasLegacyText = true;
      }
      if (typeof input.old === "string" && typeof input.new_value === "string") {
        edits.push({ oldText: input.old, newText: input.new_value });
        hasLegacyText = true;
      }

      // Normalize path
      let path = input.path || input.file_path || "";

      if (edits.length === 0) {
        throw new Error("Edit tool: Must provide at least one edit in edits array, or oldText+newText");
      }

      return {
        path,
        edits,
      };
    },
    async execute(toolCallId, params, signal, _onUpdate, ctx) {
      // Load and read file, apply edits
      const { path, edits } = params as { path: string; edits: { oldText: string; newText: string }[] };

      // Use fs/promises for file operations
      const fs = await import("fs/promises");
      const { access, readFile, writeFile } = fs;
      const { constants } = require("fs");
      const path_1 = require("path");

      const absolutePath = path_1.resolve((ctx as any).cwd || process.cwd(), path);

      // Check file access
      try {
        await access(absolutePath, constants.R_OK | constants.W_OK);
      } catch (e: any) {
        return {
          content: [{ type: "text", text: `Could not edit file: ${path}. ${e?.code ? `Error code: ${e.code}` : e.message}.` }],
          terminate: false,
        };
      }

      // Read and modify file
      const rawContent = (await readFile(absolutePath, "utf-8")).toString();
      let modifiedContent = rawContent;

      for (const edit of edits) {
        if (modifiedContent.includes(edit.oldText)) {
          modifiedContent = modifiedContent.replace(edit.oldText, edit.newText);
        }
      }

      await writeFile(absolutePath, modifiedContent, "utf-8");

      return {
        content: [{ type: "text", text: `Successfully replaced ${edits.length} block(s) in ${path}.` }],
        terminate: false,
      };
    },
  };

  // Register - this will override the built-in edit tool
  pi.registerTool(wrappedEditTool);
