/**
 * Tool Argument Autocorrect - Handles write tool parameter corrections.
 *
 * Note: Edit tool legacy format handling (old_text, new_text, old, new_value) is now
 * implemented directly in the pi-coding-agent core package's prepareEditArguments function.
 *
 * This extension handles write tool corrections only.
 *
 * Write tool:
 * - Using `file` instead of `path`
 */
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";

type WriteArgs = {
  path?: string;
  content?: unknown;
  file?: string;
  [key: string]: unknown;
};

export default function (pi: ExtensionAPI) {
  pi.on("tool_call", async (event, ctx) => {
    const input = event.input as Record<string, unknown>;

    // Handle write tool corrections
    if (event.toolName === "write") {
      const writeInput = input as WriteArgs;

      if (writeInput.file !== undefined && writeInput.path === undefined) {
        ctx.ui.notify("Auto-corrected write tool: renamed 'file' to 'path'", "info");
        event.input.path = writeInput.file;
        delete event.input.file;
      }
      return;
    }
  });
}

